export const M14_BOUNDS = {
  // M14 semantics: BASE_AMOUNT is a base multiplier (not cash).
  BASE_AMOUNT: 1.0,
  MIN_PREMIUM_MULTIPLIER: 1.0,
  MAX_PREMIUM_MULTIPLIER: 3.0,

  TRIGGER_THRESHOLD: 3,
  MULTIPLIER: 1.5,
  MAX_AMOUNT: 50_000,

  MIN_CASH_DELTA: -20_000,
  MAX_CASH_DELTA: 20_000,
  MIN_CASHFLOW_DELTA: -10_000,
  MAX_CASHFLOW_DELTA: 10_000,

  TIER_ESCAPE_TARGET: 3_000,
  REGIME_SHIFT_THRESHOLD: 500,
  BASE_DECAY_RATE: 0.02,

  BLEED_CASH_THRESHOLD: 1_000,
  FIRST_REFUSAL_TICKS: 6,
  PULSE_CYCLE: 12,

  MAX_PROCEEDS: 999_999,
  EFFECT_MULTIPLIER: 1.0,
  MIN_EFFECT: 0,
  MAX_EFFECT: 100_000,
} as const;

// ── Internal helpers (deterministic, no state mutation) ────────────────────

function m14DerivePhase(tick: number): RunPhase {
  const t = clamp(tick, 0, RUN_TOTAL_TICKS - 1);
  const third = RUN_TOTAL_TICKS / 3;
  if (t < third) return 'EARLY';
  if (t < third * 2) return 'MID';
  return 'LATE';
}

function m14DeriveRegimeFromSchedule(tick: number, schedule: MacroEvent[], fallback: MacroRegime): MacroRegime {
  if (!schedule || schedule.length === 0) return fallback;
  const sorted = [...schedule].sort((a, b) => a.tick - b.tick);
  let regime: MacroRegime = fallback;
  for (const ev of sorted) {
    if (ev.tick > tick) break;
    if (ev.regimeChange) regime = ev.regimeChange;
  }
  return regime;
}

function m14InChaosWindow(tick: number, windows: ChaosWindow[]): boolean {
  for (const w of windows ?? []) {
    if (tick >= w.startTick && tick <= w.endTick) return true;
  }
  return false;
}

function m14NormalizeSelection(sel: unknown): string[] {
  if (!sel) return [];

  if (typeof sel === 'string') return [sel];
  if (Array.isArray(sel)) return sel.filter(x => typeof x === 'string') as string[];

  if (typeof sel === 'object') {
    const o = sel as Record<string, unknown>;
    if (typeof o.id === 'string') return [o.id];
    if (Array.isArray(o.ids)) return (o.ids.filter(x => typeof x === 'string') as string[]);
  }

  return [];
}

function m14SelectActiveHandicaps(
  options: HandicapOption[],
  selectedIds: string[],
  seed: string,
  desiredCount: number,
): { active: HandicapOption[]; source: 'PLAYER' | 'DETERMINISTIC_FALLBACK' } {
  const byId = new Map(options.map(o => [o.id, o]));

  const chosen: HandicapOption[] = [];
  for (const id of selectedIds) {
    const opt = byId.get(id);
    if (opt) chosen.push(opt);
    if (chosen.length >= desiredCount) break;
  }

  if (chosen.length > 0) return { active: chosen, source: 'PLAYER' };

  const shuffled = seededShuffle(options, seed + ':handicap_opts');
  return { active: shuffled.slice(0, clamp(desiredCount, 1, Math.max(1, shuffled.length))), source: 'DETERMINISTIC_FALLBACK' };
}

function m14ComputePremiumMultiplier(
  active: HandicapOption[],
  regime: MacroRegime,
  phase: RunPhase,
  pressureTier: PressureTier,
  inChaos: boolean,
): { multiplier: number; breakdown: Record<string, unknown> } {
  const base = M14_BOUNDS.BASE_AMOUNT;

  const deltaSum = active.reduce((s, h) => s + (Number(h.cordPremiumDelta) || 0), 0);

  const phaseW = PHASE_WEIGHTS[phase] ?? 1.0;
  const pressureW = PRESSURE_WEIGHTS[pressureTier] ?? 1.0;
  const regimeW = REGIME_WEIGHTS[regime] ?? 1.0;

  const exitPulse = EXIT_PULSE_MULTIPLIERS[regime] ?? 1.0;
  const regimeMult = REGIME_MULTIPLIERS[regime] ?? 1.0;

  // Higher risk when exitPulse/regimeMult are lower.
  const regimeRisk = clamp((1 / Math.max(0.01, exitPulse)) * (1 / Math.max(0.01, regimeMult)), 0.6, 2.2);
  const chaosPenalty = inChaos ? 0.12 : 0.0;

  // Use decay as a small premium drift (keeps computeDecayRate “live” with meaningful influence).
  const decay = computeDecayRate(regime, M14_BOUNDS.BASE_DECAY_RATE);
  const drift = clamp((decay - M14_BOUNDS.BASE_DECAY_RATE) * 2.5, -0.05, 0.10);

  const weightedDelta = deltaSum * clamp(phaseW * pressureW * regimeW, 0.6, 2.4) * regimeRisk;

  const multiplier = clamp(
    base + weightedDelta + chaosPenalty + drift,
    M14_BOUNDS.MIN_PREMIUM_MULTIPLIER,
    M14_BOUNDS.MAX_PREMIUM_MULTIPLIER,
  );

  return {
    multiplier,
    breakdown: {
      base,
      deltaSum,
      weightedDelta,
      phase,
      pressureTier,
      regime,
      phaseW,
      pressureW,
      regimeW,
      exitPulse,
      regimeMult,
      regimeRisk,
      chaosPenalty,
      decay,
      drift,
    },
  };
}

// ── Exec hook ─────────────────────────────────────────────────────────────

/**
 * disadvantageDraftResolver
 *
 * Called by MechanicsRouter inside the EngineOrchestrator tick or card handler.
 * All state mutations MUST be returned in the output — never applied in place.
 * All telemetry MUST be emitted via the emit callback.
 *
 * @param input  Typed input snapshot
 * @param emit   Telemetry emitter — call for every meaningful state change
 * @returns      Typed output (all fields populated, no throws)
 */
export function disadvantageDraftResolver(input: M14Input, emit: MechanicEmitter): M14Output {
  const stateTick = clamp(((input.stateTick as number) ?? 0), 0, RUN_TOTAL_TICKS - 1);
  const stateMacroRegime = (input.stateMacroRegime as MacroRegime) ?? 'NEUTRAL';
  const statePressureTier = (input.statePressureTier as PressureTier) ?? 'LOW';

  const handicapOptions = (input.handicapOptions && input.handicapOptions.length > 0)
    ? input.handicapOptions
    : DEFAULT_HANDICAP_OPTIONS;

  const selectedIds = m14NormalizeSelection(input.playerSelection);

  const seed = computeHash(
    `M14:${stateTick}:${stateMacroRegime}:${JSON.stringify(selectedIds)}:${handicapOptions.length}`,
  );

  // Deterministic context (ties M14 into the same macro/chaos fabric as the rest of the engine)
  const macroSchedule = buildMacroSchedule(seed, MACRO_EVENTS_PER_RUN);
  const chaosWindows = buildChaosWindows(seed, CHAOS_WINDOWS_PER_RUN);

  const phase = m14DerivePhase(stateTick);
  const regime = m14DeriveRegimeFromSchedule(stateTick, macroSchedule, stateMacroRegime);
  const inChaos = m14InChaosWindow(stateTick, chaosWindows);

  // Keep pool + deck primitives live and observable.
  const pool = buildWeightedPool(
    seed + ':pool',
    (PRESSURE_WEIGHTS[statePressureTier] ?? 1.0) * (PHASE_WEIGHTS[phase] ?? 1.0),
    (REGIME_WEIGHTS[regime] ?? 1.0),
  );
  const poolPick = pool[seededIndex(seed, stateTick + 17, Math.max(1, pool.length))] ?? DEFAULT_CARD;

  const deckOrder = seededShuffle(DEFAULT_CARD_IDS, seed + ':deck');
  const deckTop = deckOrder[0] ?? DEFAULT_CARD.id;

  const oppPick = OPPORTUNITY_POOL[seededIndex(seed, stateTick + 33, OPPORTUNITY_POOL.length)] ?? DEFAULT_CARD;

  // Selection count: crisis/chaos can force more disadvantage density.
  const desiredCount = clamp(
    (regime === 'CRISIS' || inChaos ? 2 : 1) + (statePressureTier === 'CRITICAL' ? 1 : 0),
    1,
    3,
  );

  const { active: activeHandicaps, source: selectionSource } =
    m14SelectActiveHandicaps(handicapOptions, selectedIds, seed, desiredCount);

  const premium = m14ComputePremiumMultiplier(activeHandicaps, regime, phase, statePressureTier, inChaos);

  // Telemetry
  for (const h of activeHandicaps) {
    emit({
      event: 'HANDICAP_SELECTED',
      mechanic_id: 'M14',
      tick: stateTick,
      runId: '',
      payload: {
        selectionSource,
        handicap: {
          id: h.id,
          name: h.name,
          severity: h.severity,
          cordPremiumDelta: h.cordPremiumDelta,
          tags: h.tags ?? [],
        },
      },
    });
  }

  emit({
    event: 'CORD_PREMIUM_APPLIED',
    mechanic_id: 'M14',
    tick: stateTick,
    runId: '',
    payload: {
      cordPremiumMultiplier: premium.multiplier,
      breakdown: premium.breakdown,
    },
  });

  emit({
    event: 'DIFFICULTY_LOCKED',
    mechanic_id: 'M14',
    tick: stateTick,
    runId: '',
    payload: {
      seed,
      phase,
      regime,
      inChaos,
      pressureTier: statePressureTier,
      desiredCount,
      activeHandicapIds: activeHandicaps.map(h => h.id),
      cordPremiumMultiplier: premium.multiplier,
      poolPick: { id: poolPick.id, name: poolPick.name },
      oppPick: { id: oppPick.id, name: oppPick.name },
      deckTop,
    },
  });

  return {
    activeHandicaps,
    cordPremiumMultiplier: premium.multiplier,
  };
}

// ── ML companion hook ─────────────────────────────────────────────────────

export interface M14MLInput {
  activeHandicaps?: HandicapOption[];
  cordPremiumMultiplier?: number;
  runId: string;
  tick: number;
}

export interface M14MLOutput {
  score: number; // 0–1
  topFactors: string[]; // max 5 plain-English factors
  recommendation: string; // single sentence
  auditHash: string; // SHA256(inputs+outputs+rulesVersion)
  confidenceDecay: number; // 0–1, how fast this signal should decay
}

/**
 * disadvantageDraftResolverMLCompanion
 * Async advisory — fires AFTER exec_hook, reads output, returns signals only.
 * NEVER mutates state. Results feed Case File, Intel bars, and CORD scoring.
 */
export async function disadvantageDraftResolverMLCompanion(input: M14MLInput): Promise<M14MLOutput> {
  const tick = clamp(input.tick ?? 0, 0, RUN_TOTAL_TICKS - 1);

  const premium = Number(input.cordPremiumMultiplier ?? 1.0);
  const count = (input.activeHandicaps?.length ?? 0);

  const burden = clamp(((premium - 1.0) / Math.max(0.01, (M14_BOUNDS.MAX_PREMIUM_MULTIPLIER - 1.0))) * 0.7 + count * 0.12, 0, 1);
  const score = clamp(1 - burden, 0.01, 0.99);

  const confidenceDecay = computeDecayRate('NEUTRAL', M14_BOUNDS.BASE_DECAY_RATE);

  const hintIdx = seededIndex(computeHash(`M14ML:${input.runId}:${tick}:${premium}:${count}`), tick, DEFAULT_CARD_IDS.length);
  const hintCardId = DEFAULT_CARD_IDS[hintIdx] ?? DEFAULT_CARD.id;

  const topFactors = [
    `tick=${tick}/${RUN_TOTAL_TICKS}`,
    `handicaps=${count}`,
    `cordPremiumMultiplier=${premium.toFixed(2)}`,
    `burden=${burden.toFixed(2)}`,
    `hintCardId=${hintCardId}`,
  ].slice(0, 5);

  const recommendation =
    burden >= 0.75
      ? 'Difficulty is heavy: prioritize proof-first moves and avoid low-EV actions.'
      : burden >= 0.45
        ? 'Difficulty is moderate: tighten decisions and preserve optionality.'
        : 'Difficulty is light: maintain tempo and convert opportunities quickly.';

  return {
    score,
    topFactors,
    recommendation,
    auditHash: computeHash(JSON.stringify(input) + ':ml:M14'),
    confidenceDecay,
  };
}